import os
from rediscluster import RedisCluster

# Configuration
REDIS_NODES = [
    {"host": "redis-node-1", "port": 6379},
    {"host": "redis-node-2", "port": 6379},
    {"host": "redis-node-3", "port": 6379}
]

# Connect to Redis cluster
startup_nodes = REDIS_NODES
rc = RedisCluster(startup_nodes=startup_nodes, decode_responses=True)

def store_session_token(user_id, token, ttl=3600):
    """
    Store a session token in Redis with a TTL of 1 hour.
    :param user_id: Unique identifier for the user
    :param token: Session token to be stored
    :param ttl: Time to live in seconds (default is 3600 seconds or 1 hour)
    """
    rc.setex(f"session:{user_id}", ttl, token)

def retrieve_session_token(user_id):
    """
    Retrieve a session token from Redis.
    :param user_id: Unique identifier for the user
    :return: Session token if found, otherwise None
    """
    return rc.get(f"session:{user_id}")

def store_api_key(api_key, ttl=86400):
    """
    Store an API key in Redis with a TTL of 24 hours.
    :param api_key: API key to be stored
    :param ttl: Time to live in seconds (default is 86400 seconds or 24 hours)
    """
    rc.setex(f"api-key:{api_key}", ttl, "active")

def retrieve_api_key(api_key):
    """
    Retrieve an API key status from Redis.
    :param api_key: API key to be checked
    :return: 'active' if found and active, otherwise None
    """
    return rc.get(f"api-key:{api_key}")

